const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const text = clean(b.text).toLowerCase();
const dueHours = Number(clean(b.deadline_in_hours || '99999'));
const caseId = Number(clean(b.case_id || '0'));
const conflictFlag = b.conflict_flag === true;
const criticalWords = ['hoy','mañana','audiencia','embargo','desalojo','medida urgente'];
const crisisWords = ['urgente','emergencia','auxilio','grave'];
const hits = [...criticalWords, ...crisisWords].filter(w => text.includes(w));
const escalate = conflictFlag || dueHours <= 72 || hits.length > 0;
const reason = conflictFlag ? 'conflicto_potencial' : (dueHours <= 72 ? 'plazo_critico' : (hits.length > 0 ? 'lenguaje_urgente' : 'sin_riesgo'));
return [{json:{
  case_id: Number.isFinite(caseId) && caseId > 0 ? caseId : null,
  escalate,
  reason,
  due_hours: dueHours,
  hits,
  source_channel: clean(b.source_channel) || 'whatsapp',
  original_text: clean(b.text)
}}];
